function applyTestOneBridgeConfig(config){
  const refs=testOneModules();
  if(refs.input){
    refs.input.bindings.source_signal=String(config?.source_signal||refs.input.bindings.source_signal||'');
    refs.input.params.profile=String(config?.button_profile||refs.input.params.profile||'level_input');
    refs.input.params.debounce_ms=String(config?.debounce_ms||refs.input.params.debounce_ms||'50');
  }
  if(refs.timer){
    refs.timer.params.profile=String(config?.timer_profile||refs.timer.params.profile||'pulse');
    refs.timer.params.on_time_ms=String(config?.on_time_ms||refs.timer.params.on_time_ms||'5000');
    refs.timer.params.off_time_ms=String(config?.off_time_ms||refs.timer.params.off_time_ms||'0');
    refs.timer.params.stop_policy=String(config?.stop_policy||refs.timer.params.stop_policy||'finish_current_pulse');
  }
  if(refs.output){
    refs.output.bindings.output_target=String(config?.output_target||refs.output.bindings.output_target||'');
    refs.output.bindings.feedback=String(config?.feedback||refs.output.bindings.feedback||'');
  }
}
