async function materializePulseRateModule(){const module=moduleById(state.ui.moduleSelected);if(!module||module.template!=='pulse_rate_extractor')return;const params=module.params||{},bindings=module.bindings||{},sourceA=normalizeRuntimeBinding(bindings.source_a),sourceB=normalizeRuntimeBinding(bindings.source_b),qualitySource=normalizeRuntimeBinding(bindings.quality_source),sourceMode=mapPulseSourceMode(params.source_mode),profile=params.output_profile||'rate_engineering',thresholdOn=parseFloat(params.threshold_on||'0.8'),thresholdOff=parseFloat(params.threshold_off||'0.4'),edgeMode=params.edge_mode||'rising',units=params.engineering_units||'',digitalStateId=module.id+'_digital_state',countId=module.id+'_count_total',rateId=module.id+'_rate_engineering',totalId=module.id+'_total_engineering',windowId=module.id+'_window_average',pulsesPerRevolution=parseFloat(params.pulses_per_revolution||'0'),pulsesPerUnit=parseFloat(params.pulses_per_unit||'0');if(!sourceA){alert('Нужно привязать источник A.');return}if(sourceMode==='analog_diff_pair'&&!sourceB){alert('Для analog_diff_pair нужен источник B.');return}if(profile==='rate_engineering'&&String(units).toLowerCase()==='rpm'&&(!Number.isFinite(pulsesPerRevolution)||pulsesPerRevolution<=0)){alert('Для RPM нужен параметр "Имп/оборот".');return}if(profile==='flow_totalized'&&(!Number.isFinite(pulsesPerUnit)||pulsesPerUnit<=0)){alert('Для flow_totalized нужен параметр "Имп/единицу".');return}const requests=[{block_id:module.id+'_extract',type:'signal_extractor',mode:sourceMode,input:sourceA,input_b:sourceB,quality_input:qualitySource,threshold_on:thresholdOn,threshold_off:thresholdOff,output:digitalStateId}];if(profile==='count_total'||profile==='rate_engineering'||profile==='flow_totalized'){requests.push({block_id:module.id+'_count',type:'counter',mode:edgeMode,input:digitalStateId,reset_input:'',compare_value:1,compare_value_b:0,output:countId})}if(profile==='rate_engineering'||profile==='flow_totalized'){let scale=1;const lowerUnits=String(units).toLowerCase();if(lowerUnits==='rpm'&&Number.isFinite(pulsesPerRevolution)&&pulsesPerRevolution>0)scale=1/pulsesPerRevolution;else if(Number.isFinite(pulsesPerUnit)&&pulsesPerUnit>0)scale=1/pulsesPerUnit;requests.push({block_id:module.id+'_rate',type:'rate_estimator',mode:choosePulseRateMode(units),input:countId,duration_ms:1000,compare_value:scale,compare_value_b:1,output:rateId})}if(profile==='flow_totalized'){const durationMinutes=Math.max(parseInt(params.window_value||'1440',10)||1440,1),durationMs=durationMinutes*60000,bucketMs=chooseWindowBucketMs(durationMs);requests.push({block_id:module.id+'_total',type:'totalizer',mode:'delta',input:countId,reset_input:'',compare_value:1/pulsesPerUnit,compare_value_b:0,output:totalId});requests.push({block_id:module.id+'_window',type:'window_aggregator',mode:'average',input:rateId,period_ms:bucketMs,duration_ms:durationMs,compare_value:1,output:windowId})}for(const payload of requests){await getJson('/block-definition',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)})}await loadAll()}
async function materializeCyclicOutputModule(){const module=moduleById(state.ui.moduleSelected);if(!module||module.template!=='cyclic_output_manual')return;const params=module.params||{},bindings=module.bindings||{},runEnable=normalizeRuntimeBinding(bindings.run_enable),autoMenuEnable=normalizeRuntimeBinding(bindings.auto_menu_enable),manualHold=normalizeRuntimeBinding(bindings.manual_hold),manualToggle=normalizeRuntimeBinding(bindings.manual_toggle),outputTarget=normalizeRuntimeBinding(bindings.output_target),manualProfile=params.manual_profile||'hold_level',onTimeMs=Math.max(parseInt(params.on_time_ms||'5000',10)||5000,1),cyclePeriodMs=Math.max(parseInt(params.cycle_period_ms||'300000',10)||300000,onTimeMs),startImmediately=boolParam(params.start_immediately,true),autoEnableId=module.id+'_auto_enable',autoActiveId=module.id+'_auto_active',manualStateId=module.id+'_manual_state',commandStateId=module.id+'_command_state';if(!outputTarget){alert('Нужно привязать "Выходной канал".');return}const timerEnable=runEnable&&autoMenuEnable?autoEnableId:(runEnable||autoMenuEnable),requests=[];if(timerEnable){if(runEnable&&autoMenuEnable){requests.push({block_id:module.id+'_auto_enable',type:'logic_gate',mode:'and',input:runEnable,input_b:autoMenuEnable,output:autoEnableId})}requests.push({block_id:module.id+'_auto',type:'timer',mode:'interval_while_enabled',trigger:'',enable:timerEnable,duration_ms:onTimeMs,period_ms:cyclePeriodMs,start_immediately:startImmediately,output:autoActiveId})}else{requests.push({block_id:module.id+'_auto',type:'timer',mode:'interval',trigger:'',enable:'',duration_ms:onTimeMs,period_ms:cyclePeriodMs,start_immediately:startImmediately,output:autoActiveId})}if(manualProfile==='toggle_press'){if(manualToggle){requests.push({block_id:module.id+'_manual_latch',type:'latch',mode:'toggle',toggle_input:manualToggle,output:manualStateId})}else{requests.push({block_id:module.id+'_manual_latch',type:'latch',mode:'toggle',toggle_input:'',output:manualStateId})}}else{if(manualHold){requests.push({block_id:module.id+'_manual_passthrough',type:'logic_gate',mode:'or',input:manualHold,input_b:manualHold,output:manualStateId})}else{requests.push({block_id:module.id+'_manual_latch',type:'latch',mode:'toggle',toggle_input:'',output:manualStateId})}}requests.push({block_id:module.id+'_command_signal',type:'logic_gate',mode:'or',input:autoActiveId,input_b:manualStateId,output:commandStateId});requests.push({block_id:module.id+'_command_output',type:'logic_gate',mode:'or',input:autoActiveId,input_b:manualStateId,output:outputTarget});for(const payload of requests){await getJson('/block-definition',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)})}await loadAll()}
function miniLinks(items,mode){if(!items.length)return'<div class="module-link-mini empty">-</div>';return items.map(l=>mode==='out'?'<div class="module-link-mini"><span>'+escapeHtml(l.sourceOutput)+'</span><b>'+escapeHtml(roleLabel(l.role))+'</b><span>'+escapeHtml(l.targetId+'.'+l.targetBinding)+'</span></div>':'<div class="module-link-mini"><span>'+escapeHtml(l.sourceId+'.'+l.sourceOutput)+'</span><b>'+escapeHtml(roleLabel(l.role))+'</b><span>'+escapeHtml(l.targetBinding)+'</span></div>').join('')}
function laneClass(validation,lane){const statuses=lane.modules.map(id=>validationForModule(validation,id)?.stateLabel).filter(Boolean);if(statuses.includes('invalid'))return'danger';if(statuses.includes('warning'))return'warn';if(statuses.includes('incomplete')||statuses.includes('isolated'))return'idle';return'ok'}
function laneText(validation,lane){const statuses=lane.modules.map(id=>validationForModule(validation,id)?.stateLabel).filter(Boolean);if(statuses.includes('invalid'))return'Есть invalid узлы';if(statuses.includes('warning'))return'Есть warning узлы';if(statuses.includes('incomplete'))return'Есть incomplete узлы';if(statuses.includes('isolated'))return'Есть isolated узлы';return'Готово'}
function flowNodeClass(moduleState){if(!moduleState)return'idle';if(moduleState.stateLabel==='invalid')return'danger';if(moduleState.stateLabel==='warning')return'warn';if(moduleState.stateLabel==='incomplete'||moduleState.stateLabel==='isolated')return'idle';return'ok'}
function renderFlowNode(validation,moduleId){const module=moduleById(moduleId),template=templateById(module?.template),moduleState=validationForModule(validation,moduleId);if(!module||!template)return'<div class="module-flow-card idle"><div class="module-flow-card-head"><strong>Missing module</strong>'+badge('missing','warning')+'</div><div class="muted-line">Этот узел ещё не создан в workspace.</div></div>';const incoming=links().filter(l=>l.targetId===module.id),outgoing=links().filter(l=>l.sourceId===module.id),keyBindings=(template.bindings||[]).slice(0,2).map(([key,label])=>'<div class="module-flow-meta-row"><span>'+escapeHtml(label)+'</span><strong>'+escapeHtml(String(module.bindings[key]||'-'))+'</strong></div>').join('');return'<div class="module-flow-card '+flowNodeClass(moduleState)+(state.ui.moduleSelected===module.id?' selected':'')+'"><button class="module-flow-card-button" data-module-select="'+module.id+'"><div class="module-flow-card-head"><div><strong>'+escapeHtml(module.label)+'</strong><div class="muted-line">'+escapeHtml(template.label)+'</div></div>'+badge(moduleState?.stateLabel||'idle',moduleState?.stateLabel||'warning')+'</div><div class="module-pills"><span class="module-pill">'+escapeHtml(module.capability)+'</span><span class="module-pill">'+incoming.length+' in / '+outgoing.length+' out</span></div><div class="module-status-row">'+badge(moduleState?.message||'Нет данных.',moduleState?.stateLabel||'warning')+'</div><div class="module-flow-meta">'+(keyBindings||'<div class="module-flow-meta-row"><span>Bindings</span><strong>-</strong></div>')+'</div></button></div>'}
function renderLane(validation,lane){const laneLinks=links().filter(l=>lane.modules.includes(l.sourceId)&&lane.modules.includes(l.targetId));const parts=[];lane.modules.forEach((id,index)=>{parts.push(renderFlowNode(validation,id));if(index<lane.modules.length-1){parts.push('<div class="module-flow-arrow">→</div>');parts.push('<div class="module-flow-slot"><span>+ Вставить модуль</span><small>между узлами</small></div>');parts.push('<div class="module-flow-arrow">→</div>')}});return'<div class="module-flow-lane '+laneClass(validation,lane)+'"><div class="module-flow-lane-head"><div><h4>'+escapeHtml(lane.label)+'</h4><p>'+escapeHtml(lane.note)+'</p></div>'+badge(laneText(validation,lane),laneClass(validation,lane))+'</div><div class="module-flow-row">'+parts.join('')+'</div><div class="module-flow-links"><span class="caps">Связей внутри lane: '+laneLinks.length+'</span></div></div>'}
function renderFlowView(validation){if(workspace().preset==='boiler_pilot')return'<div class="section-card" style="margin-top:12px"><h3>Flow View v1</h3><p class="muted-line">Это первый живой перенос boiler-примера из docs в UI. Здесь видны не raw blocks, а lane механизма: demand, горение, топливо, уровень воды, trip policy и chemistry.</p><div class="module-flow-board">'+FLOW_LANES.map(lane=>renderLane(validation,lane)).join('')+'</div></div>';if(workspace().preset==='flowmeter_demo'||workspace().preset==='fan_rpm_demo'||workspace().preset==='cyclic_output_demo')return'<div class="section-card" style="margin-top:12px"><h3>Flow View</h3><p class="muted-line">'+(workspace().preset==='cyclic_output_demo'?'Здесь проверяется, что простой recipe-модуль можно развернуть в реальные <b>timer / latch / logic_gate</b> без sequence-first перегруза.':'Для этого demo пока важнее inspector и русская справка шаблона. Здесь проверяется, что один и тот же reusable template можно использовать как <b>Flowmeter</b> или как <b>Fan RPM</b> без лишних полей в UI.')+'</p><div class="module-card-grid">'+modules().map(module=>{const template=templateById(module.template),moduleState=validationForModule(validation,module.id);return'<div class="module-card"><button class="module-card-button" data-module-select="'+module.id+'"><div class="module-card-head"><div><strong>'+escapeHtml(module.label)+'</strong><div class="muted-line">'+escapeHtml(template.label)+'</div></div>'+badge(moduleState.stateLabel,moduleState.stateLabel)+'</div><div class="module-status-row">'+badge(moduleState.message,moduleState.stateLabel)+'</div></button></div>'}).join('')+'</div></div>';return'<div class="section-card" style="margin-top:12px"><h3>Flow View</h3><div class="note" style="margin-top:12px">Живой lane-based Flow View v1 сейчас подготовлен для Boiler Pilot. Для остальных preset пока главным экраном остаются library, inspector и typed links.</div></div>'}
function setStatus(validation){const host=$('modulesStatus');if(host)host.innerHTML='Workspace: <b>'+escapeHtml(workspace().label)+'</b>. Модулей: <b>'+validation.modules.length+'</b>, ready: <b>'+validation.readyModules+'</b>, incomplete: <b>'+validation.incompleteModules+'</b>, invalid: <b>'+validation.invalidModules+'</b>, links error: <b>'+validation.errorLinks+'</b>.'}
function renderSummary(validation){const familyCounts={};modules().forEach(m=>familyCounts[m.family]=(familyCounts[m.family]||0)+1);$('modulesSummary').innerHTML='<div class="module-topline"><div><h3 style="margin:0">Пространство модулей</h3><p>Собирай механизм из функциональных модулей. Физика живёт в Channels/Signals, а пользовательская модель и логические связи должны быть понятны здесь.</p></div><div class="module-view-switches">'+['operation','service','logic'].map(view=>'<button data-module-view="'+view+'" class="'+(state.ui.moduleView===view?'active':'')+'">'+({operation:'Операция',service:'Сервис',logic:'Логика'})[view]+'</button>').join('')+'</div></div><div class="module-summary-grid"><div class="stat-card"><b>Workspace</b><span>'+escapeHtml(workspace().label)+'</span></div><div class="stat-card"><b>Модули</b><span>'+modules().length+'</span></div><div class="stat-card"><b>Связи</b><span>'+links().length+'</span></div><div class="stat-card"><b>Семейства</b><span>'+Object.keys(familyCounts).length+'</span></div><div class="stat-card"><b>Ready</b><span>'+validation.readyModules+'</span></div><div class="stat-card"><b>Incomplete</b><span>'+validation.incompleteModules+'</span></div><div class="stat-card"><b>Invalid</b><span>'+validation.invalidModules+'</span></div><div class="stat-card"><b>Link errors</b><span>'+validation.errorLinks+'</span></div></div>'}
function renderLibrary(){const selectedFamily=state.ui.moduleFamilyFilter||'all',search=(state.ui.moduleTemplateSearch||'').trim().toLowerCase(),families=FAMILY_UI_REGISTRY.map(entry=>{const count=Object.values(TEMPLATES).filter(template=>template.family===entry.id).length;return Object.assign({},entry,{count})}),visibleFamilies=families.filter(entry=>selectedFamily==='all'||entry.id===selectedFamily),showTemplates=selectedFamily!=='all'||!!search,visibleTemplates=Object.entries(TEMPLATES).filter(([,template])=>{if(selectedFamily!=='all'&&template.family!==selectedFamily)return false;if(!search)return true;const haystack=[template.label,template.desc,template.family].join(' ').toLowerCase();return haystack.includes(search)}),templatesByFamily=showTemplates?visibleFamilies.map(entry=>({entry,templates:visibleTemplates.filter(([,template])=>template.family===entry.id)})).filter(group=>group.templates.length):[],activeEntry=families.find(entry=>entry.id===selectedFamily),quickStartVisible=isBlankBuildableWorkspace(),quickStartIds=['button_input','timer_primitive','discrete_output','cyclic_output_manual'];const chips='<div class="module-family-chips"><button class="module-family-chip'+(selectedFamily==='all'?' active':'')+'" data-module-family="all">Все шаблоны</button>'+families.map(entry=>'<button class="module-family-chip'+(selectedFamily===entry.id?' active':'')+'" data-module-family="'+entry.id+'"><span>'+escapeHtml(entry.title)+'</span><small>'+entry.count+'</small></button>').join('')+'</div>';const summary='<div class="module-library-summary"><div><strong>'+(activeEntry?escapeHtml(activeEntry.title):'Каталог шаблонов')+'</strong><p>'+(activeEntry?escapeHtml(activeEntry.summary):(quickStartVisible?'Начни с кирпичиков ниже. На уровне платформы входы и выходы не разные миры, а одна I/O-точка с разной ролью в сценарии.':'Сначала выбери смысловую группу сверху. Так библиотека останется короткой даже когда шаблонов станет много.'))+'</p></div><label>Поиск шаблона<input id="moduleTemplateSearch" type="text" placeholder="Например: температура, RPM, насос" value="'+escapeHtml(state.ui.moduleTemplateSearch||'')+'"></label></div>';const quickStart=quickStartVisible?'<div class="module-library-group"><h4>Быстрый старт простого сценария</h4><p>Нажми карточку ниже, чтобы сразу добавить кирпичик в текущий Main. Блок остаётся видимым, пока ты собираешь базовую тройку.</p><div class="module-template-list">'+quickStartIds.map(id=>{const template=TEMPLATES[id];return template?'<button type="button" class="module-template-btn" data-add-module="'+id+'"><strong>Добавить: '+escapeHtml(template.label)+'</strong><small>'+escapeHtml(template.desc)+'</small></button>':''}).join('')+'</div></div>':'';const groups=!showTemplates?'<div class="note">Выбери группу сверху или начни поиск, чтобы открыть нужные шаблоны.</div>':templatesByFamily.length?templatesByFamily.map(group=>'<div class="module-library-group"><h4>'+escapeHtml(group.entry.title)+'</h4><p>'+escapeHtml(group.entry.summary)+'</p><div class="module-template-list">'+group.templates.map(([id,template])=>'<button type="button" class="module-template-btn" data-add-module="'+id+'"><strong>'+escapeHtml(template.label)+'</strong><small>'+escapeHtml(template.desc)+'</small></button>').join('')+'</div></div>').join(''):'<div class="note">По этому фильтру шаблоны не найдены.</div>';$('moduleLibrary').innerHTML=chips+summary+quickStart+groups}
function renderSimpleScenarioLane(validation,title,cls,items){return'<section class="scenario-lane '+cls+'"><h4>'+escapeHtml(title)+'</h4>'+(items.length?items.map(module=>{const template=templateById(module.template),moduleState=validationForModule(validation,module.id);return'<button class="scenario-node'+(state.ui.moduleSelected===module.id?' selected':'')+'" data-module-select="'+module.id+'"><strong>'+escapeHtml(module.label)+'</strong><div class="muted-line">'+escapeHtml(template.label)+'</div><div class="module-status-row">'+badge(moduleState.stateLabel,moduleState.stateLabel)+'</div></button>'}).join(''):'<div class="note">Пока пусто.</div>')+'</section>'}
function renderSimpleScenarioOperation(validation){const sourceModules=modules().filter(m=>m.family==='operator_io'||m.family==='measured_value'),logicModules=modules().filter(m=>m.family==='onoff_control'||m.family==='sequence'||m.family==='pid_control'||m.family==='signal_processing'),outputModules=modules().filter(m=>m.family==='actuator'||m.family==='alarm_policy'||m.family==='protocol_interface');return'<div class="module-topline"><div><h3 style="margin:0">Main</h3><p>Это первый спокойный workspace для простого проекта: слева источники, в центре логика, справа команды и исполнение. На уровне платформы это не другой мир, а та же I/O-точка в другой роли.</p></div><div class="module-view-switches"><button class="active">Scenario-first</button></div></div><div class="scenario-topline"><span class="module-pill">Проект: '+escapeHtml(workspace().label||'Простой проект')+'</span><span class="module-pill">Root: Main</span><span class="module-pill">ON</span><span class="module-pill">AUTO</span></div><div class="scenario-simple-grid"><div class="scenario-project section-card"><h3>Проект</h3><div class="scenario-project-tree"><button class="scenario-tree-node active">Main</button><button class="scenario-tree-node">+ Child sequence позже</button></div><div class="note">С этого места пользователь начинает проект и не обязан сразу думать про Blocks.</div></div><div class="scenario-workspace section-card"><h3>Workspace</h3><div class="scenario-lanes">'+renderSimpleScenarioLane(validation,'Источники','sources',sourceModules)+renderSimpleScenarioLane(validation,'Логика','logic',logicModules)+renderSimpleScenarioLane(validation,'Команды / Исполнение','outputs',outputModules)+'</div><div class="note" style="margin-top:12px">Этот же путь теперь работает и в demo, и в пустом Main, если в workspace собрана тройка: источник, таймер и команда.</div></div></div>'}
function renderOperation(validation){if(!modules().length){$('moduleOperationView').innerHTML='<div class="module-topline"><div><h3 style="margin:0">Операция</h3><p>Создай модуль или загрузи demo workspace.</p></div></div><div class="note" style="margin-top:12px">Пока модулей нет.</div>';return}if(isTestOneWorkspace()){$('moduleOperationView').innerHTML=renderSimpleScenarioOperation(validation);return}$('moduleOperationView').innerHTML='<div class="module-topline"><div><h3 style="margin:0">Операция</h3><p>Здесь модуль должен читаться как часть механизма, а не как технический объект.</p></div></div><div class="module-card-grid">'+modules().map(module=>{const template=templateById(module.template),moduleState=validationForModule(validation,module.id),outputs=(template.outputs||[]).slice(0,4).map(([,label])=>'<span class="module-pill">'+escapeHtml(label)+'</span>').join('');return'<div class="module-card'+(state.ui.moduleSelected===module.id?' selected':'')+'"><button class="module-card-button" data-module-select="'+module.id+'"><div class="module-card-head"><div><strong>'+escapeHtml(module.label)+'</strong><div class="muted-line">'+escapeHtml(template.label)+'</div></div>'+badge(moduleState.stateLabel,moduleState.stateLabel)+'</div><div class="module-pills"><span class="module-pill">'+escapeHtml(module.capability)+'</span><span class="module-pill">'+escapeHtml(module.backend)+'</span></div><div class="module-status-row">'+badge(moduleState.message,moduleState.stateLabel)+'</div><div class="module-outputs">'+outputs+'</div></button><div class="module-links"><div class="module-link-row"><span class="caps">Входящих: '+moduleState.incomingCount+' | Исходящих: '+moduleState.outgoingCount+'</span></div><div class="module-link-row"><button class="ghost" data-module-select="'+module.id+'" data-module-open-view="service">Сервис</button><button class="ghost" data-module-select="'+module.id+'" data-module-open-view="logic">Логика</button></div></div></div>'}).join('')+'</div>'}
function renderService(validation){const module=moduleById(state.ui.moduleSelected);if(!module){$('moduleServiceView').innerHTML='<div class="module-topline"><div><h3 style="margin:0">Сервис</h3><p>Выбери модуль, чтобы увидеть его связи и назначение.</p></div></div><div class="note" style="margin-top:12px">Модуль не выбран.</div>';return}const template=templateById(module.template),family=MODULE_FAMILIES.find(x=>x.id===module.family),moduleState=validationForModule(validation,module.id);$('moduleServiceView').innerHTML='<div class="module-topline"><div><h3 style="margin:0">Сервис</h3><p>Сервисный слой объясняет: что модуль получает, что он публикует и почему участвует в механизме.</p></div></div><div class="kv" style="margin-top:12px"><div><span>Модуль</span><strong>'+escapeHtml(module.label)+'</strong></div><div><span>Шаблон</span><strong>'+escapeHtml(template.label)+'</strong></div><div><span>Семейство</span><strong>'+escapeHtml(family?.label||module.family)+'</strong></div><div><span>Backend</span><strong>'+escapeHtml(module.backend)+'</strong></div><div><span>Authority</span><strong>'+escapeHtml(module.authority)+'</strong></div><div><span>Статус настройки</span><strong>'+escapeHtml(moduleState.stateLabel)+'</strong></div></div><div class="section-card" style="margin-top:12px"><h3>Валидация модуля</h3><div class="validation-list" style="margin-top:12px">'+moduleState.bindings.map(result=>'<div class="validation-item '+sev(result.severity)+'"><strong>'+escapeHtml(result.label)+'</strong><span>'+escapeHtml(result.message)+'</span></div>').join('')+'</div></div><div class="grid" style="margin-top:12px"><div class="section-card"><h3>Привязки</h3><div class="kv" style="margin-top:12px">'+(template.bindings||[]).map(([key,label])=>'<div><span>'+escapeHtml(label)+'</span><strong>'+escapeHtml(module.bindings[key]||'-')+'</strong></div>').join('')+'</div></div><div class="section-card"><h3>Публикуемые выходы</h3><div class="kv" style="margin-top:12px">'+(template.outputs||[]).map(([key,label])=>'<div><span>'+escapeHtml(label)+'</span><strong>'+escapeHtml(module.id+'.'+key)+'</strong></div>').join('')+'</div></div></div>'}
function renderLogic(validation){const draft=state.ui.moduleLinkDraft,sourceOutputs=templateById(moduleById(draft.sourceId)?.template)?.outputs||[],targetBindings=templateById(moduleById(draft.targetId)?.template)?.bindings||[];$('moduleLogicView').innerHTML='<div class="module-topline"><div><h3 style="margin:0">Логика</h3><p>Физический I/O сначала заводится в <b>Channels</b>, затем нормализуется в <b>Signals</b>, и уже после этого привязывается в <b>Modules</b>. Для сценария "если температура выше порога, делаем 1, если ниже, делаем 2" используй шаблон <b>Порог / Окно</b>.</p></div></div>'+renderFlowView(validation)+'<div class="module-card-grid">'+(modules().length?modules().map(module=>{const template=templateById(module.template),moduleState=validationForModule(validation,module.id),incoming=links().filter(l=>l.targetId===module.id),outgoing=links().filter(l=>l.sourceId===module.id);return'<div class="module-card'+(state.ui.moduleSelected===module.id?' selected':'')+'"><button class="module-card-button" data-module-select="'+module.id+'"><div class="module-card-head"><div><strong>'+escapeHtml(module.label)+'</strong><div class="muted-line">'+escapeHtml(template.label)+'</div></div>'+badge(moduleState.stateLabel,moduleState.stateLabel)+'</div><div class="module-pills"><span class="module-pill">'+escapeHtml(module.id)+'</span><span class="module-pill">'+incoming.length+' in / '+outgoing.length+' out</span></div><div class="module-status-row">'+badge(moduleState.message,moduleState.stateLabel)+'</div></button><div class="module-links"><div class="module-link-group"><div class="caps">Входящие</div>'+miniLinks(incoming,'in')+'</div><div class="module-link-group"><div class="caps">Исходящие</div>'+miniLinks(outgoing,'out')+'</div><div class="module-link-row"><button class="ghost" data-module-duplicate="'+module.id+'">Дублировать</button><button class="ghost" data-module-delete="'+module.id+'">Удалить</button></div></div></div>'}).join(''):'<div class="note">Пока модулей нет.</div>')+'</div><div class="section-card" style="margin-top:12px"><h3>Карта зависимостей выбранного модуля</h3>'+selectedDependencyMap(state.ui.moduleSelected)+'</div><div class="section-card" style="margin-top:12px"><h3>Конструктор typed links</h3><div class="form-grid" style="margin-top:12px"><label>Модуль-источник<select id="moduleLinkSource">'+modules().map(module=>'<option value="'+module.id+'" '+(draft.sourceId===module.id?'selected':'')+'>'+escapeHtml(module.label)+'</option>').join('')+'</select></label><label>Выход источника<select id="moduleLinkOutput">'+sourceOutputs.map(([key,label])=>'<option value="'+key+'" '+(draft.sourceOutput===key?'selected':'')+'>'+escapeHtml(label)+'</option>').join('')+'</select></label><label>Роль<select id="moduleLinkRole">'+LINK_ROLES.map(role=>'<option value="'+role.value+'" '+(draft.role===role.value?'selected':'')+'>'+role.label+'</option>').join('')+'</select></label><label>Модуль-цель<select id="moduleLinkTarget">'+modules().map(module=>'<option value="'+module.id+'" '+(draft.targetId===module.id?'selected':'')+'>'+escapeHtml(module.label)+'</option>').join('')+'</select></label><label>Привязка цели<select id="moduleLinkBinding">'+targetBindings.map(([key,label])=>'<option value="'+key+'" '+(draft.targetBinding===key?'selected':'')+'>'+escapeHtml(label)+'</option>').join('')+'</select></label></div><div class="actions" style="margin-top:12px"><button id="addModuleTypedLink" class="primary">Добавить связь</button><span class="caps">Связь сразу подставляет binding в целевой модуль.</span></div></div><div class="section-card" style="margin-top:12px"><h3>Список связей</h3><div class="stack" style="margin-top:12px">'+(validation.links.length?validation.links.map(result=>{const link=workspace().links.find(entry=>entry.id===result.id);return'<div class="module-link-row"><span><strong>'+escapeHtml(link.sourceId+'.'+link.sourceOutput)+'</strong> <span class="caps">'+escapeHtml(roleLabel(link.role))+'</span> -> '+escapeHtml(link.targetId+'.'+link.targetBinding)+'</span><span class="module-inline-status">'+badge(result.message,result.severity)+'</span><button class="ghost" data-remove-link="'+result.id+'">Удалить</button></div>'}).join(''):'<div class="note">Пока нет связей.</div>')+'</div></div>'}
function renderInspector(validation){const module=moduleById(state.ui.moduleSelected);if(!module){$('moduleInspector').innerHTML='<h3>Инспектор модуля</h3><div class="note" style="margin-top:12px">Выбери модуль, чтобы настроить backend, authority, параметры и привязки.</div>';return}const template=templateById(module.template),family=MODULE_FAMILIES.find(x=>x.id===module.family),moduleState=validationForModule(validation,module.id),help=TEMPLATE_HELP[module.template],testOneCard=isTestOneWorkspace()?renderTestOneWizard(validation):'';const helpCard=help?'<div class="section-card" style="margin-top:12px"><h3>Русская справка шаблона</h3><div class="kv" style="margin-top:12px"><div><span>Что делает</span><strong>'+escapeHtml(help.what)+'</strong></div><div><span>Когда использовать</span><strong>'+escapeHtml(help.when)+'</strong></div><div><span>Что нужно привязать</span><strong>'+escapeHtml(help.bind)+'</strong></div><div><span>Что выдаёт</span><strong>'+escapeHtml(help.outputs)+'</strong></div><div><span>Типичные ошибки</span><strong>'+escapeHtml(help.mistakes)+'</strong></div></div></div>':'';const runtimeCard=module.template==='pulse_rate_extractor'?'<div class="section-card" style="margin-top:12px"><h3>Runtime pack</h3><div class="note" style="margin-top:12px">Этот шаблон может сразу развернуться в реальные blocks поверх текущего runtime.</div><div class="stack" style="margin-top:12px">'+pulseRuntimePreview(module).map(item=>'<div class="module-link-row"><span>'+escapeHtml(item)+'</span></div>').join('')+'</div><div class="actions" style="margin-top:12px"><button id="materializePulseRateModule" class="primary">Создать runtime pack</button><span class="caps">Создаст или обновит blocks для extraction / count / rate / total / window по текущему профилю.</span></div></div>':module.template==='cyclic_output_manual'?'<div class="section-card" style="margin-top:12px"><h3>Runtime pack</h3><div class="note" style="margin-top:12px">Этот шаблон разворачивается в реальные blocks: timer, optional latch и два logic_gate для publish + channel output.</div><div class="stack" style="margin-top:12px">'+cyclicRuntimePreview(module).map(item=>'<div class="module-link-row"><span>'+escapeHtml(item)+'</span></div>').join('')+'</div><div class="actions" style="margin-top:12px"><button id="materializeCyclicOutputModule" class="primary">Создать runtime pack</button><span class="caps">Создаст или обновит blocks для циклического выхода и ручного режима.</span></div></div>':'';$('moduleInspector').innerHTML='<h3>Инспектор модуля</h3>'+testOneCard+'<div class="section-card" style="margin-top:12px"><h3>Как привязывать модуль</h3><div class="note" style="margin-top:12px">1. Физические входы и выходы сначала создаются в <b>Channels</b>. 2. Если нужен нормализованный сигнал, он создаётся в <b>Signals</b>. 3. Здесь модуль привязывается уже к <b>signal:*</b>, <b>channel:*</b> или <b>module:*</b>. То есть модуль работает не по проводам напрямую, а по нормализованным точкам экосистемы.</div></div>'+helpCard+runtimeCard+'<div class="form-grid" style="margin-top:12px"><label>ID модуля<input type="text" value="'+escapeHtml(module.id)+'" readonly></label><label>Название<input type="text" data-module-field="label" value="'+escapeHtml(module.label)+'"></label><label>Семейство<input type="text" value="'+escapeHtml(family?.label||module.family)+'" readonly></label><label>Шаблон<input type="text" value="'+escapeHtml(template.label)+'" readonly></label><label>Backend<select data-module-field="backend">'+BACKENDS.map(value=>'<option value="'+value+'" '+(module.backend===value?'selected':'')+'>'+value+'</option>').join('')+'</select></label><label>Authority<select data-module-field="authority">'+AUTHORITIES.map(value=>'<option value="'+value+'" '+(module.authority===value?'selected':'')+'>'+value+'</option>').join('')+'</select></label><label>Capability<select data-module-field="capability">'+CAPABILITIES.map(value=>'<option value="'+value+'" '+(module.capability===value?'selected':'')+'>'+value+'</option>').join('')+'</select></label><label>Заметки<input type="text" data-module-field="notes" value="'+escapeHtml(module.notes||'')+'" placeholder="Сервисная заметка или назначение"></label></div><div class="section-card" style="margin-top:12px"><h3>Статус и валидация</h3><div class="module-status-row" style="margin-top:12px">'+badge(moduleState.stateLabel,moduleState.stateLabel)+badge(moduleState.message,moduleState.stateLabel)+'</div><div class="validation-list" style="margin-top:12px">'+moduleState.bindings.map(result=>'<div class="validation-item '+sev(result.severity)+'"><strong>'+escapeHtml(result.label)+'</strong><span>'+escapeHtml(result.message)+'</span></div>').join('')+'</div></div><div class="section-card" style="margin-top:12px"><h3>Привязки</h3><div class="form-grid" style="margin-top:12px">'+((template.bindings||[]).map(([key,label,placeholder,type])=>{const listId='moduleBindingList_'+module.id+'_'+key;return'<label>'+escapeHtml(label)+'<input type="text" data-module-binding="'+key+'" list="'+listId+'" value="'+escapeHtml(module.bindings[key]||'')+'" placeholder="'+escapeHtml(placeholder)+'"><datalist id="'+listId+'">'+suggestions(type).map(value=>'<option value="'+escapeHtml(value)+'"></option>').join('')+'</datalist></label>'}).join('')||'<div class="note">У этого шаблона нет привязок.</div>')+'</div></div><div class="section-card" style="margin-top:12px"><h3>Параметры логики</h3><div class="form-grid" style="margin-top:12px">'+((template.params||[]).map(([key,label,placeholder])=>'<label>'+escapeHtml(label)+'<input type="text" data-module-param="'+key+'" value="'+escapeHtml(module.params[key]||'')+'" placeholder="'+escapeHtml(placeholder)+'"></label>').join('')||'<div class="note">У этого шаблона пока нет отдельных параметров.</div>')+'</div><div class="note" style="margin-top:12px">Именно здесь должны жить пороги, окна, Kp/Ki/Kd, таймауты и прочие понятные пользователю настройки модуля.</div></div><div class="section-card" style="margin-top:12px"><h3>Публикуемые выходы</h3><div class="module-outputs" style="margin-top:12px">'+((template.outputs||[]).map(([key,label])=>'<span class="module-pill">'+escapeHtml(label)+' = '+escapeHtml(module.id+'.'+key)+'</span>').join('')||'<span class="module-pill">Нет выходов</span>')+'</div></div><div class="section-card" style="margin-top:12px"><h3>Переход к низкоуровневым слоям</h3><p class="muted-line">Ниже — быстрые кнопки, если нужно провалиться к движку напрямую.</p><div class="actions" style="margin-top:12px">'+((template.tabs||[]).map(tab=>'<button class="ghost" data-switch-tab="'+tab+'">'+({channels:'Channels',signals:'Signals',blocks:'Blocks',alarms:'Alarms',display:'Display',sequences:'Sequences',comms:'Comms'})[tab]+'</button>').join('')||'<span class="caps">Для этого шаблона не указаны дополнительные вкладки.</span>')+'</div></div><div class="actions" style="margin-top:12px"><button class="ghost" data-module-duplicate="'+module.id+'">Дублировать</button><button class="ghost" data-module-delete="'+module.id+'">Удалить</button></div>'}
function updateView(){$('moduleOperationView')?.classList.toggle('hidden',state.ui.moduleView!=='operation');$('moduleServiceView')?.classList.toggle('hidden',state.ui.moduleView!=='service');$('moduleLogicView')?.classList.toggle('hidden',state.ui.moduleView!=='logic')}
function renderModules(){if(!$('tab-modules'))return;ensure();syncDraft();const validation=collectValidation();setStatus(validation);renderSummary(validation);renderLibrary();renderOperation(validation);renderService(validation);renderLogic(validation);renderInspector(validation);updateView()}
function click(event){const addTemplate=event.target?.closest?.('[data-add-module]')?.dataset?.addModule,selectModule=event.target?.closest?.('[data-module-select]')?.dataset?.moduleSelect,duplicate=event.target?.closest?.('[data-module-duplicate]')?.dataset?.moduleDuplicate,del=event.target?.closest?.('[data-module-delete]')?.dataset?.moduleDelete,remove=event.target?.closest?.('[data-remove-link]')?.dataset?.removeLink,view=event.target?.closest?.('[data-module-view]')?.dataset?.moduleView,switchTo=event.target?.closest?.('[data-switch-tab]')?.dataset?.switchTab,openView=event.target?.closest?.('[data-module-open-view]')?.dataset?.moduleOpenView,familyChip=event.target?.closest?.('[data-module-family]')?.dataset?.moduleFamily;if(addTemplate){addModule(addTemplate);renderModules();return}if(selectModule){state.ui.moduleSelected=selectModule;if(openView)state.ui.moduleView=openView;syncDraft();renderModules();return}if(duplicate){duplicateModule(duplicate);renderModules();return}if(del){deleteModule(del);renderModules();return}if(remove){removeLink(remove);renderModules();return}if(view){state.ui.moduleView=view;renderModules();return}if(familyChip){state.ui.moduleFamilyFilter=familyChip;renderModules();return}if(switchTo){switchTab(switchTo);return}if(event.target?.id==='refreshModules'){renderModules();return}if(event.target?.id==='seedTestOneModules'){seedTestOne();renderModules();return}if(event.target?.id==='testOneAutofill'){testOneAutofill();renderModules();return}if(event.target?.id==='testOneCreateInputResources'){createTestOneInputResources().then(()=>renderModules()).catch(e=>alert(e.message));return}if(event.target?.id==='testOneCreateOutputChannel'){createTestOneOutputChannel().then(()=>renderModules()).catch(e=>alert(e.message));return}if(event.target?.id==='testOneMaterialize'){materializeTestOne().then(()=>renderModules()).catch(e=>alert(e.message));return}if(event.target?.id==='testOneOpenSignals'){switchTab('signals');return}if(event.target?.id==='testOneOpenChannels'){switchTab('channels');return}if(event.target?.id==='seedBoilerModules'){seedBoiler();renderModules();return}if(event.target?.id==='seedFlowmeterModules'){seedFlowmeter();renderModules();return}if(event.target?.id==='seedFanRpmModules'){seedFanRpm();renderModules();return}if(event.target?.id==='seedCyclicOutputModules'){seedCyclicOutput();renderModules();return}if(event.target?.id==='resetModulesWorkspace'){resetWorkspace();renderModules();return}if(event.target?.id==='materializePulseRateModule'){materializePulseRateModule().then(()=>renderModules()).catch(e=>alert(e.message));return}if(event.target?.id==='materializeCyclicOutputModule'){materializeCyclicOutputModule().then(()=>renderModules()).catch(e=>alert(e.message));return}if(event.target?.id==='addModuleTypedLink'){addLink();renderModules()}}
function change(event){const field=event.target?.dataset?.moduleField,binding=event.target?.dataset?.moduleBinding,param=event.target?.dataset?.moduleParam,module=moduleById(state.ui.moduleSelected),testRefs=testOneModules(),wizard=ensureTestOneWizardState();if(event.target?.id==='moduleTemplateSearch'){state.ui.moduleTemplateSearch=event.target.value;renderLibrary();return}if(event.target?.id==='moduleLinkSource'){state.ui.moduleLinkDraft.sourceId=event.target.value;syncDraft();renderModules();return}if(event.target?.id==='moduleLinkOutput'){state.ui.moduleLinkDraft.sourceOutput=event.target.value;renderModules();return}if(event.target?.id==='moduleLinkRole'){state.ui.moduleLinkDraft.role=event.target.value;renderModules();return}if(event.target?.id==='moduleLinkTarget'){state.ui.moduleLinkDraft.targetId=event.target.value;syncDraft();renderModules();return}if(event.target?.id==='moduleLinkBinding'){state.ui.moduleLinkDraft.targetBinding=event.target.value;renderModules();return}if(event.target?.id==='testOneInputSignal'&&testRefs.input){testRefs.input.bindings.source_signal=event.target.value;renderModules();return}if(event.target?.id==='testOneButtonProfile'&&testRefs.input){testRefs.input.params.profile=event.target.value;renderModules();return}if(event.target?.id==='testOneDebounceMs'&&testRefs.input){testRefs.input.params.debounce_ms=event.target.value;renderModules();return}if(event.target?.id==='testOneTimerProfile'&&testRefs.timer){testRefs.timer.params.profile=event.target.value;renderModules();return}if(event.target?.id==='testOneOnTime'&&testRefs.timer){testRefs.timer.params.on_time_ms=event.target.value;renderModules();return}if(event.target?.id==='testOneOffTime'&&testRefs.timer){testRefs.timer.params.off_time_ms=event.target.value;renderModules();return}if(event.target?.id==='testOneStopPolicy'&&testRefs.timer){testRefs.timer.params.stop_policy=event.target.value;renderModules();return}if(event.target?.id==='testOneOutputChannel'&&testRefs.output){testRefs.output.bindings.output_target=event.target.value;renderModules();return}if(event.target?.id==='testOneFeedbackSignal'&&testRefs.output){testRefs.output.bindings.feedback=event.target.value;renderModules();return}if(event.target?.id==='testOneCreateInputChannelId'){wizard.inputChannelId=event.target.value;renderModules();return}if(event.target?.id==='testOneCreateInputGpio'){wizard.inputGpio=event.target.value;renderModules();return}if(event.target?.id==='testOneCreateInputPullup'){wizard.inputPullup=event.target.checked;renderModules();return}if(event.target?.id==='testOneCreateInputInverted'){wizard.inputInverted=event.target.checked;renderModules();return}if(event.target?.id==='testOneCreateOutputChannelId'){wizard.outputChannelId=event.target.value;renderModules();return}if(event.target?.id==='testOneCreateOutputGpio'){wizard.outputGpio=event.target.value;renderModules();return}if(event.target?.id==='testOneCreateOutputInverted'){wizard.outputInverted=event.target.checked;renderModules();return}if(event.target?.id==='testOneCreateOutputInitial'){wizard.outputInitial=event.target.checked;renderModules();return}if(field&&module){module[field]=event.target.value;renderModules();return}if(binding&&module){module.bindings[binding]=event.target.value;renderModules();return}if(param&&module){module.params[param]=event.target.value;renderModules()}}
const root=$('tab-modules');
if(root&&!root.dataset.modulesBound){root.dataset.modulesBound='1';root.addEventListener('click',click);root.addEventListener('change',change)}
